const scrapeResult = $('HTTP: Firecrawl Scrape').item.json;
const claudeResult = items[0].json;
const recordId = $('Supabase: Create brand_intelligence Record').item.json[0] && $('Supabase: Create brand_intelligence Record').item.json[0].id;

var analysis = { tone_detected: null, keywords_extracted: [], content_structure: {}, confidence_scores: { tone: 0, keywords: 0 } };
try {
  var content = (claudeResult.content && claudeResult.content[0] && claudeResult.content[0].text) ? claudeResult.content[0].text : '{}';
  var jsonMatch = content.match(/\{[\s\S]*\}/);
  analysis = JSON.parse(jsonMatch ? jsonMatch[0] : content);
} catch(e) {}

var anyLowConfidence = Object.values(analysis.confidence_scores || {}).some(function(v) { return v < 0.6; });
var status = scrapeResult && scrapeResult.error ? 'failed' : (anyLowConfidence ? 'needs_review' : 'complete');

return [{
  json: {
    record_id: recordId,
    analysis: analysis,
    screenshot_url: (scrapeResult && scrapeResult.data && scrapeResult.data.screenshot) ? scrapeResult.data.screenshot : null,
    status: status,
    needs_review: anyLowConfidence
  }
}];
